def merge_sort(arr):
    if len(arr) <= 1:
        return arr

    mid = len(arr) // 2
    left = merge_sort(arr[:mid])
    right = merge_sort(arr[mid:])

    return merge(left, right)

def merge(left, right):
    result = []
    i = j = 0

    while i < len(left) and j < len(right):
        if left[i] <= right[j]:
            result.append(left[i])
            i += 1
        else:
            result.append(right[j])
            j += 1

    result.extend(left[i:])
    result.extend(right[j:])
    return result

# Recurrence: T(n) = 2T(n/2) + O(n)
# Solution: T(n) = O(n log n)

#include <stdio.h>

void printPairs(int arr[], int n) {
    // Time Complexity: O(n²)
    for (int i = 0; i < n; i++) {        // Outer loop: n times
        for (int j = 0; j < n; j++) {    // Inner loop: n times per outer iteration
            printf("(%d, %d)", arr[i], arr[j]);
        }
    }
}

// For comparison - O(n³) would have three nested loops
void printTriples(int arr[], int n) {
    for (int i = 0; i < n; i++)
        for (int j = 0; j < n; j++)
            for (int k = 0; k < n; k++)
                printf("(%d, %d, %d)", arr[i], arr[j], arr[k]);
}

// Recurrence for n²: T(n) = T(n-1) + O(n) = O(n²)
// Recurrence for n³: T(n) = T(n-1) + O(n²) = O(n³)

public class DynamicArray<T> {
    private Object[] array;
    private int size = 0;
    private int capacity = 1;

    public void add(T element) {
        // When array is full, double its size
        if (size == capacity) {
            resize(2 * capacity);  // O(n) operation - copy all elements
        }
        array[size] = element;
        size++;
    }

    private void resize(int newCapacity) {
        Object[] newArray = new Object[newCapacity];
        for (int i = 0; i < size; i++) {
            newArray[i] = array[i];
        }
        array = newArray;
        capacity = newCapacity;
    }

    // Amortized analysis:
    // n insertions cost: n + 2 + 4 + 8 + ... + 2^k <= 2n
    // Amortized cost per operation: O(1)
    // Worst case: O(n) for single expensive resize
    // Average/Aggregate: O(1) per operation
}
